proof fn phi_1_set_map_union_external_body_trusted(s1: Set<int>, s2: Set<int>, f: spec_fn(int) -> int)
    ensures
        (s1 + s2).map(f) == s1.map(f) + s2.map(f),
{
    set_map_union(s1, s2, f);
}

proof fn phi_2_map_union_empty_left<A, B>(s: Set<A>, f: spec_fn(A) -> B)
    ensures
        (Set::<A>::empty() + s).map(f) == s.map(f),
{
    set_map_union(Set::<A>::empty(), s, f);
    assert(Set::<A>::empty().map(f) =~= Set::<B>::empty());
}

proof fn phi_3_map_union_idempotent<A, B>(s: Set<A>, f: spec_fn(A) -> B)
    ensures
        (s + s).map(f) == s.map(f),
{
    set_map_union(s, s, f);
}

proof fn phi_4_map_union_subset_left<A, B>(s1: Set<A>, s2: Set<A>, f: spec_fn(A) -> B)
    ensures
        s1.map(f).subset_of((s1 + s2).map(f)),
{
    set_map_union(s1, s2, f);
}

proof fn phi_5_auto_lemma_universal_instantiation(s1: Set<int>, s2: Set<int>, s3: Set<int>, f: spec_fn(int) -> int)
    ensures
        (s1 + s2 + s3).map(f) == s1.map(f) + s2.map(f) + s3.map(f),
{
    set_map_union_auto::<int, int>();
